import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
} from 'recharts';

const data = [
  { name: 'Янв', value: 120 },
  { name: 'Фев', value: 190 },
  { name: 'Мар', value: 300 },
];

export default function MyChart() {
  return (
    <LineChart width={500} height={300} data={data}>
      <CartesianGrid />
      <XAxis dataKey="name" />
      <YAxis />
      <Tooltip />
      <Line dataKey="value" />
    </LineChart>
  );
}
